mapper.select:
SELECT t.ID AS id, t.QUOTA_CODE AS quotaCode, t.PROJECT_NAME AS projectName, t.PROJECT_CONTENT AS projectContent, t.UNIT AS unit, t.AMOUNT_EXCLUDING_TAX AS amountExcludingTax, t.STATUS AS status, t.CREATE_BY AS createBy, t.CREATE_TIME AS createTime, t.UPDATE_BY AS updateBy, t.UPDATE_TIME AS updateTime FROM E_IC_TENANCE_PROJECT_QUOTA t WHERE 1 = 1
AND t.QUOTA_CODE LIKE #{qcLike}
AND t.PROJECT_NAME LIKE #{pnLike}
AND t.STATUS =#{status}
ORDER BY t.CREATE_TIME DESC, t.ID DESC
